// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.TxnManager.Txn;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Storage-level tests for prefix-run scans over LMDB statement indexes.
 */
public class LmdbPrefixRunIteratorTest {

	@TempDir
	File dataDir;

	private TripleStore tripleStore;

	@BeforeEach
	public void setUp() throws Exception {
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc,posc"), null);
	}

	@Test
	public void poscPrefixLengthOneEmitsOnePredicateRun() throws Exception {
		storeDefaultRows();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			LmdbPrefixRunPlan plan = tripleStore.prefixRunPlan(new int[] { TripleIndex.PRED_IDX }, -1, -1, -1, -1);

			ScanResult result = collect(tripleStore.getPrefixRuns(txn, plan, -1, -1, -1, -1, true, false));

			assertThat(result.values(TripleIndex.PRED_IDX)).containsExactly(10L, 20L, 30L);
			assertThat(result.rows).hasSize(3);
			// bulk prefetch may read the whole (tiny) index into one batch; sub-linearity on long runs is
			// covered by longRunsStillSkipSubLinearly
			assertThat(result.rowsScanned).isLessThanOrEqualTo(6);
		}
	}

	@Test
	public void longRunsStillSkipSubLinearly() throws Exception {
		tripleStore.startTransaction();
		for (int i = 0; i < 3000; i++) {
			tripleStore.storeTriple(100 + i, 10, 1000 + i, 1, true);
		}
		tripleStore.storeTriple(100, 20, 1000, 1, true);
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			LmdbPrefixRunPlan plan = tripleStore.prefixRunPlan(new int[] { TripleIndex.PRED_IDX }, -1, -1, -1, -1);

			ScanResult result = collect(tripleStore.getPrefixRuns(txn, plan, -1, -1, -1, -1, true, false));

			assertThat(result.values(TripleIndex.PRED_IDX)).containsExactly(10L, 20L);
			assertThat(result.rowsScanned).isLessThan(500);
		}
	}

	@Test
	public void poscPrefixLengthTwoEmitsPredicateObjectRuns() throws Exception {
		storeDefaultRows();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			LmdbPrefixRunPlan plan = tripleStore.prefixRunPlan(new int[] { TripleIndex.PRED_IDX, TripleIndex.OBJ_IDX },
					-1, -1, -1, -1);

			ScanResult result = collect(tripleStore.getPrefixRuns(txn, plan, -1, -1, -1, -1, true, false));

			assertThat(result.pairs(TripleIndex.PRED_IDX, TripleIndex.OBJ_IDX))
					.containsExactly("10/1000", "10/1001", "20/2000", "30/3000");
			assertThat(result.rows).hasSize(4);
			assertThat(result.rowsScanned).isLessThanOrEqualTo(6);
		}
	}

	@Test
	public void poscPrefixLengthThreeEmitsPredicateObjectSubjectRuns() throws Exception {
		storeDefaultRows();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			LmdbPrefixRunPlan plan = tripleStore.prefixRunPlan(
					new int[] { TripleIndex.PRED_IDX, TripleIndex.OBJ_IDX, TripleIndex.SUBJ_IDX }, -1, -1, -1,
					-1);

			ScanResult result = collect(tripleStore.getPrefixRuns(txn, plan, -1, -1, -1, -1, true, false));

			assertThat(result.triples(TripleIndex.PRED_IDX, TripleIndex.OBJ_IDX, TripleIndex.SUBJ_IDX))
					.containsExactly("10/1000/100", "10/1000/101", "10/1001/102", "20/2000/200",
							"20/2000/201", "30/3000/300");
			assertThat(result.rows).hasSize(6);
		}
	}

	@Test
	public void prefixSeekCarriesWhenLastPrefixComponentOverflows() throws Exception {
		tripleStore.startTransaction();
		tripleStore.storeTriple(100, 10, Long.MAX_VALUE, 1, true);
		tripleStore.storeTriple(101, 11, 1, 1, true);
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			LmdbPrefixRunPlan plan = tripleStore.prefixRunPlan(new int[] { TripleIndex.PRED_IDX, TripleIndex.OBJ_IDX },
					-1, -1, -1, -1);

			ScanResult result = collect(tripleStore.getPrefixRuns(txn, plan, -1, -1, -1, -1, true, false));

			assertThat(result.pairs(TripleIndex.PRED_IDX, TripleIndex.OBJ_IDX))
					.containsExactly("10/" + Long.MAX_VALUE, "11/1");
		}
	}

	@Test
	public void seekToSkipsAheadToRequestedValue() throws Exception {
		storeDefaultRows();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			LmdbPrefixRunPlan plan = tripleStore.prefixRunPlan(new int[] { TripleIndex.PRED_IDX }, -1, -1, -1, -1);

			try (LmdbPrefixRunIterator cursor = tripleStore.getPrefixRuns(txn, plan, -1, -1, -1, -1, true, false)) {
				assertThat(cursor.seekTo(15L)).isTrue();
				assertThat(cursor.next()).isTrue();
				assertThat(cursor.quad()[TripleIndex.PRED_IDX]).isEqualTo(20L);
				// seeking to an existing value positions on exactly that value
				assertThat(cursor.seekTo(30L)).isTrue();
				assertThat(cursor.next()).isTrue();
				assertThat(cursor.quad()[TripleIndex.PRED_IDX]).isEqualTo(30L);
				// seeking past the last value: the cursor either reports exhaustion immediately (the bulk
				// prefetch already saw the end) or on the next advance
				if (cursor.seekTo(31L)) {
					assertThat(cursor.next()).isFalse();
				}
				assertThat(cursor.seekTo(10L)).isFalse();
			}
		}
	}

	@Test
	public void seekToWithBoundPredicateSkipsWithinObjectRuns() throws Exception {
		storeDefaultRows();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			LmdbPrefixRunPlan plan = tripleStore.prefixRunPlan(new int[] { TripleIndex.OBJ_IDX }, -1, 10, -1, -1);

			try (LmdbPrefixRunIterator cursor = tripleStore.getPrefixRuns(txn, plan, -1, 10, -1, -1, true, false)) {
				assertThat(cursor.next()).isTrue();
				assertThat(cursor.quad()[TripleIndex.OBJ_IDX]).isEqualTo(1000L);
				assertThat(cursor.seekTo(1001L)).isTrue();
				assertThat(cursor.next()).isTrue();
				assertThat(cursor.quad()[TripleIndex.OBJ_IDX]).isEqualTo(1001L);
				assertThat(cursor.next()).isFalse();
			}
		}
	}

	private void storeDefaultRows() throws Exception {
		tripleStore.startTransaction();
		tripleStore.storeTriple(100, 10, 1000, 1, true);
		tripleStore.storeTriple(101, 10, 1000, 1, true);
		tripleStore.storeTriple(102, 10, 1001, 1, true);
		tripleStore.storeTriple(200, 20, 2000, 1, true);
		tripleStore.storeTriple(201, 20, 2000, 1, true);
		tripleStore.storeTriple(300, 30, 3000, 1, true);
		tripleStore.commit();
	}

	private static ScanResult collect(LmdbPrefixRunIterator iterator) throws Exception {
		try (LmdbPrefixRunIterator cursor = iterator) {
			List<long[]> rows = new ArrayList<>();
			while (cursor.next()) {
				rows.add(Arrays.copyOf(cursor.quad(), 4));
			}
			return new ScanResult(rows, cursor.getSourceRowsScannedActual());
		}
	}

	private record ScanResult(List<long[]> rows, long rowsScanned) {

		private List<Long> values(int field) {
			return rows.stream().map(row -> row[field]).toList();
		}

		private List<String> pairs(int first, int second) {
			return rows.stream().map(row -> row[first] + "/" + row[second]).toList();
		}

		private List<String> triples(int first, int second, int third) {
			return rows.stream().map(row -> row[first] + "/" + row[second] + "/" + row[third]).toList();
		}
	}
}
